(111, 'widget_custom_html', 'a:3:{i:2;a:2:{s:5:\"title\";s:0:\"\";s:7:\"content\";s:1436:\"<div id=\"carouselExampleIndicators\" class=\"carousel slide\" data-ride=\"carousel\">\r\n  <ol class=\"carousel-indicators\">\r\n    <li data-target=\"#carouselExampleIndicators\" data-slide-to=\"0\" class=\"active\"></li>\r\n    <li data-target=\"#carouselExampleIndicators\" data-slide-to=\"1\"></li>\r\n    <li data-target=\"#carouselExampleIndicators\" data-slide-to=\"2\"></li>\r\n  </ol>\r\n  <div class=\"carousel-inner\">\r\n    <div class=\"carousel-item active\">\r\n      <img src=\"http://localhost/thietbitheduc/wp-content/uploads/2020/11/1946d0b89a7652e4cd29fbc76b33b3f5.jpg\" class=\"d-block w-100\" alt=\"#\">\r\n    </div>\r\n    <div class=\"carousel-item\">\r\n      <img src=\"http://localhost/thietbitheduc/wp-content/uploads/2020/11/88edf05347441f9a12aeff02e6eb7bb7.jpg\" class=\"d-block w-100\" alt=\"#\">\r\n    </div>\r\n    <div class=\"carousel-item\">\r\n      <img src=\"http://localhost/thietbitheduc/wp-content/uploads/2020/11/51bc9ce5e8e317945e5f43da732898f3.jpg\" class=\"d-block w-100\" alt=\"#\">\r\n    </div>\r\n  </div>\r\n  <a class=\"carousel-control-prev\" href=\"#carouselExampleIndicators\" role=\"button\" data-slide=\"prev\">\r\n    <span class=\"carousel-control-prev-icon\" aria-hidden=\"true\"></span>\r\n    <span class=\"sr-only\">Previous</span>\r\n  </a>\r\n  <a class=\"carousel-control-next\" href=\"#carouselExampleIndicators\" role=\"button\" data-slide=\"next\">\r\n    <span class=\"carousel-control-next-icon\" aria-hidden=\"true\"></span>\r\n    <span class=\"sr-only\">Next</span>\r\n  </a>\r\n</div>\";}i:3;a:2:{s:5:\"title\";s:0:\"\";s:7:\"content\";s:7876:\"<div class=\"wiget-sidebar\">\r\n                        <img src=\"http://localhost/thietbitheduc/wp-content/uploads/2020/11/38c1ae927b838318321df83bef0fd5d1.jpg\" alt=\"#\" class=\"it-2020\">\r\n                        <div class=\"catalogue\">\r\n                            <h2>Catalogue</h2>\r\n                            <div class=\"english\">\r\n                                <h3>English</h3>\r\n                                <div class=\"gach\"></div>\r\n                                <a href=\"#\"><img src=\"http://localhost/thietbitheduc/wp-content/uploads/2020/11/f2b90876148cec1cc3a928c4564b7ae0.jpg\" alt=\"#\"\r\n                                        class=\"img-fluid\"></a>\r\n                                <div class=\"gach\"></div>\r\n                            </div>\r\n                            <div class=\"japan\">\r\n                                <h3>Japanese</h3>\r\n                                <div class=\"gach\"></div>\r\n                                <a href=\"#\"><img src=\"http://localhost/thietbitheduc/wp-content/uploads/2020/11/f2b90876148cec1cc3a928c4564b7ae0.jpg\" alt=\"#\"\r\n                                        class=\"img-fluid\"></a>\r\n                                <div class=\"gach\"></div>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"teaching-schedule\">\r\n                            <h2>Lịch</h2>\r\n                            <h3>Trực khoa</h3>\r\n                            <div class=\"gach\"></div>\r\n                            <div class=\"body-teaching-schedule\">\r\n                                <div class=\"schedule-title\">\r\n                                    <table class=\"table\">\r\n                                        <thead>\r\n                                            <tr>\r\n                                                <th scope=\"col\">\r\n                                                    <b>Họ & Tên (Chức vụ)</b> </th>\r\n\r\n                                                <th scope=\"col\">\r\n                                                    <b>Thời gian</b><br>\r\n                                                    <span class=\"text-yellow\">Buổi</span><span\r\n                                                        class=\"text-blue\">Thứ</span></th>\r\n                                            </tr>\r\n                                        </thead>\r\n                                        <tbody>\r\n                                            <tr>\r\n                                                <th scope=\"row\">Lê Diên Tâm <br>\r\n                                                    <i>(Q.Trưởng khoa)</i></th>\r\n                                                <td><span class=\"text-yellow\">Chiều</span><span class=\"text-blue\">Thứ\r\n                                                        4</span>\r\n                                                    <span class=\"text-yellow\">Sáng</span><span class=\"text-blue\">Thứ\r\n                                                        5</span>\r\n                                                    <span class=\"text-yellow\">Sáng</span><span class=\"text-blue\">Thứ\r\n                                                        6</span>\r\n                                                    <span class=\"text-yellow\">Sáng</span><span class=\"text-blue\">Thứ\r\n                                                        7</span>\r\n                                                </td>\r\n\r\n                                            </tr>\r\n                                            <tr>\r\n                                                <th scope=\"row\">Phan Thị Thể\r\n                                                    <br><i>(Phó Trưởng khoa)</i></th>\r\n                                                <td><span class=\"text-yellow\">Sáng</span><span class=\"text-blue\">Thứ\r\n                                                        2</span>\r\n                                                    <span class=\"text-yellow\">Chiều</span><span class=\"text-blue\">Thứ\r\n                                                        6</span></td>\r\n                                            </tr>\r\n                                            <tr>\r\n                                                <th scope=\"row\">Nguyễn Huy Hoàng\r\n                                                    <i>(Trưởng Bộ môn Công nghệ phần mềm)</i></th>\r\n                                                <td><span class=\"text-yellow\">Chiều</span><span class=\"text-blue\">Thứ\r\n                                                        2</span>\r\n                                                    <span class=\"text-yellow\">Chiều</span><span class=\"text-blue\">Thứ\r\n                                                        3</span></td>\r\n\r\n                                            </tr>\r\n                                            <tr>\r\n                                                <th scope=\"row\">Nguyễn Thanh Vũ\r\n                                                    <i>(Trưởng Bộ môn Mạng máy tính)</i></th>\r\n                                                <td><span class=\"text-yellow\">Chiều</span><span class=\"text-blue\">Thứ\r\n                                                        5</span>\r\n                                                </td>\r\n\r\n                                            </tr>\r\n                                            <tr>\r\n                                                <th scope=\"row\">Nguyễn Phong Lan\r\n                                                    <i>(Trưởng Bộ môn Đồ họa)</i></th>\r\n                                                <td><span class=\"text-yellow\">Sáng</span><span class=\"text-blue\">Thứ\r\n                                                        4</span></td>\r\n\r\n                                            </tr>\r\n                                            <tr>\r\n                                                <th scope=\"row\">Lâm Thị Phương Thảo\r\n                                                    <i>(Trưởng Bộ môn Tin học cơ sở)</i></th>\r\n                                                <td><span class=\"text-yellow\">Sáng</span><span class=\"text-blue\">Thứ\r\n                                                        5</span></td>\r\n\r\n                                            </tr>\r\n                                        </tbody>\r\n                                    </table>\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n                        <div class=\"event\">\r\n                            <h2>Sự kiện</h2>\r\n                            <h3>Hoạt động</h3>\r\n                            <div class=\"gach\"></div>\r\n                            <div class=\"row\">\r\n\r\n                                <div class=\"col-md col title-event\">&ensp;</div>\r\n                                <div class=\"col-md col content-event\">&ensp;</div>\r\n\r\n                            </div>\r\n                            <div class=\"gach\"></div>\r\n\r\n                        </div>\r\n                        <div class=\"recruitment\">\r\n                            <h2>Tuyển dụng</h2>\r\n                            <h3>Cơ hội việc làm</h3>\r\n													<div class=\"gach\"></div><div class=\"recruitment-content\">\r\n                           [widget id=\"rpwe_widget-4\"]     \r\n                            </div>\r\n                        </div>\r\n                        <div class=\"alumni-need\">\r\n                            <h2>Cựu sinh viên\r\n                            </h2>\r\n                            <h3> thông tin cần biết</h3>\r\n                            <div class=\"gach\"></div><div class=\"alumni-need-content\">\r\n                                [widget id=\"rpwe_widget-3\"]\r\n                            </div>\r\n                        </div>\r\n                    </div>\";}s:12:\"_multiwidget\";i:1;}', 'yes'),
