(158, 1, '2020-11-03 17:38:43', '2020-11-03 17:38:43', '<!-- wp:html -->\n<div class=\"home-page\">\n        <div class=\"container\">\n            <div class=\"row\">\n                <!-- left-home -->\n                <div class=\"left-home col-md-4\">\n                     [widget id=\"custom_html-3\"]\n                </div>\n                 <div class=\"right-home col-md-8\">\n                  <div class=\"news\">\n                        <h2>Tin tức\n                        </h2>\n                        <h3>Thông báo</h3>\n                        <div class=\"news-post\">\n\n                        </div>\n                    </div>\n                    <div class=\"school-introduction\">\n                        <h2>Khoa Công nghệ thông tin\n\n                        </h2>\n                        <h3>Trường Cao đẳng Công nghệ Thủ Đức</h3>\n                        <div class=\"gach\"></div>\n\n                       \n                    \n<!-- /wp:html -->\n\n<!-- wp:core-embed/youtube {\"url\":\"https://www.youtube.com/watch?v=cm57ye-svYI\\u0026feature=youtu.be\\u0026ab_channel=KhoaC%C3%B4ngngh%E1%BB%87th%C3%B4ngtin-C%C4%90C%C3%B4ngngh%E1%BB%87Th%E1%BB%A7%C4%90%E1%BB%A9c\",\"type\":\"video\",\"providerNameSlug\":\"youtube\",\"className\":\"aligncenter wp-embed-aspect-16-9 wp-has-aspect-ratio\"} -->\n<figure class=\"wp-block-embed-youtube wp-block-embed is-type-video is-provider-youtube aligncenter wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\nhttps://www.youtube.com/watch?v=cm57ye-svYI&amp;feature=youtu.be&amp;ab_channel=KhoaC%C3%B4ngngh%E1%BB%87th%C3%B4ngtin-C%C4%90C%C3%B4ngngh%E1%BB%87Th%E1%BB%A7%C4%90%E1%BB%A9c\n</div></figure>\n<!-- /wp:core-embed/youtube -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>&lt;div class=\"school-introduction-content\">\n                            &lt;p> Với lịch sử phát triển hơn 15 năm, Khoa Công nghệ thông tin (FIT-TDC) là một trong những\n                            