(192, 1, '2020-11-04 01:03:44', '2020-11-04 01:03:44', '<!-- wp:paragraph -->\n<p>ác sinh viên vui lòng xem danh sách bên dưới và có mặt lúc&nbsp;<strong>8giờ30 sáng ngày thứ bảy 31/10/2020 tại phòng B301B</strong>&nbsp;để nghe phổ biến về nội dung học tập.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:table -->\n<figure class=\"wp-block-table\"><table><tbody><tr><td>MSSV</td><td>Họ lót</td><td>Tên</td></tr><tr><td>20211TM4780</td><td>Trương Thái</td><td>Anh</td></tr><tr><td>20211TT0954</td><td>Nguyễn Thị Lan</td><td>Anh</td></tr><tr><td>20211TT0723</td><td>Nguyễn Văn</td><td>Bảo</td></tr><tr><td>20211TT1290</td><td>Nguyễn Minh</td><td>Đức</td></tr><tr><td>20211TT1564</td><td>Não Thị Thùy</td><td>Dung</td></tr><tr><td>20211TT1927</td><td>Lương Quốc</td><td>Hoài</td></tr><tr><td>20211TT1283</td><td>Trần Quốc</td><td>Huy</td></tr><tr><td>20211TT1527</td><td>Vũ Duy</td><td>Khanh</td></tr><tr><td>20211TT0892</td><td>Bùi Duy</td><td>Khánh</td></tr><tr><td>20211TT1579</td><td>Trần Văn</td><td>Khiêm</td></tr><tr><td>20211TT2029</td><td>Nguyễn Thành</td><td>Lộc</td></tr><tr><td>20211TT0219</td><td>Đổng Xuân</td><td>Lời</td></tr><tr><td>20211TT3887</td><td>Đoàn Trần Ngọc</td><td>Long</td></tr><tr><td>20211TT0108</td><td>Nguyễn Văn</td><td>Long</td></tr><tr><td>20211TT4200</td><td>Phạm Thị Quỳnh</td><td>Nga</td></tr><tr><td>20211TT2875</td><td>Lê Tuấn</td><td>Nghị</td></tr><tr><td>20211TT3358</td><td>Nguyễn Thị Tình</td><td>Nhi</td></tr><tr><td>20211TT0503</td><td>Diệp Thanh</td><td>Phong</td></tr><tr><td>20211TT2545</td><td>Nguyễn Huy</td><td>Phong</td></tr><tr><td>20211TT3015</td><td>Trương Thành</td><td>Phú</td></tr><tr><td>20211TT4420</td><td>Phạm Nguyễn Hoàng</td><td>Phú</td></tr><tr><td>20211TT2194</td><td>Đỗ Hoàng Nhật</td><td>Phương</td></tr><tr><td>20211TT1151</td><td>Tô Hoài</td><td>Phương</td></tr><tr><td>20211TT1169</td><td>Phạm Thị Nhã</td><td>Phương</td></tr><tr><td>20211TM4665</td><td>Huỳnh Mai Thanh</td><td>Tâm</td></tr><tr><td>20211TT3348</td><td>Lê Nguyễn Thảo</td><td>Tâm</td></tr><tr><td>20211TT2353</td><td>Lê Đức</td><td>Thắng</td></tr><tr><td>20211TT1477</td><td>Hà Minh</td><td>Thắng</td></tr><tr><td>20211TT1281</td><td>Trần Nhật</td><td>Thanh</td></tr><tr><td>20211TT0263</td><td>Trương Văn</td><td>Tiến</td></tr><tr><td>20211TT0755</td><td>Nguyễn Thị Linh</td><td>Trang</td></tr><tr><td>20211TT2529</td><td>Nguyễn Thị Minh</td><td>Trúc</td></tr><tr><td>20211TT0102</td><td>Hàng Thanh</td><td>Tuấn</td></tr><tr><td>20211TT4326</td><td>Trịnh Anh</td><td>Tuấn</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:paragraph -->\n<p>Các bạn không có tên trong danh sách, Khoa Công nghệ thông tin chân thành cảm ơn các bạn đã đăng ký tham gia chương trình. Hy vọng các bạn sẽ tiếp tục nỗ lực và học tốt chương trình hiện tại.<em><strong>FIT-TDC</strong></em></p>\n<!-- /wp:paragraph -->', 'Danh sách trúng tuyển Chương trình CNTT IT-TFT Nhật Bản 2020', '', 'inherit', 'closed', 'closed', '', '190-revision-v1', '', '', '2020-11-04 01:03:44', '2020-11-04 01:03:44', '', 190, 'http://localhost/thietbitheduc/2020/11/04/190-revision-v1/', 0, 'revision', '', 0),
(193, 1, '2020-11-04 01:05:22', '2020-11-04 01:05:22', '<!-- wp:html -->\n<div class=\"home-page\">\n   <div class=\"container\">\n      <div class=\"row\">\n         <!-- left-home -->\n         <div class=\"left-home col-md-4\">\n            [widget id=\"custom_html-3\"]\n         </div>\n         <div class=\"right-home col-md-8\">\n            <div class=\"news\">\n               <h2>Tin tức\n               </h2>\n               <h3>Thông báo</h3>\n               <div class=\"news-post\">\n<div class=\"row\">\n<div class=\"col-md-6 col-6\" style=\"\n    border-right: 1px solid #86d8da;\">[widget id=\"rpwe_widget-5\"]</div>\n<div class=\"col-md-6 col-6\">[widget id=\"rpwe_widget-6\"]</div>\n</div>\n[widget id=\"rpwe_widget-7\"]\n\n               </div>\n            </div>\n            <div class=\"school-introduction\">\n               <h2>Khoa Công nghệ thông tin\n               </h2>\n               <h3>Trường Cao đẳng Công nghệ Thủ Đức</h3>\n               <div class=\"gach\"></div>\n               <figure class=\"wp-block-embed-youtube wp-block-embed is-type-video is-provider-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\">\n                  <div class=\"wp-block-embed__wrapper\">\n                     https://www.youtube.com/watch?v=cm57ye-svYI&amp;feature=youtu.be&amp;ab_channel=KhoaC%C3%B4ngngh%E1%BB%87th%C3%B4ngtin-C%C4%90C%C3%B4ngngh%E1%BB%87Th%E1%BB%A7%C4%90%E1%BB%A9c\n                  </div>\n               </figure>\n               <div class=\"school-introduction-content\">\n                  <p> Với lịch sử phát triển hơn 15 năm, Khoa Công nghệ thông tin (FIT-TDC) là một trong những\n                     khoa mũi nhọn, đào tạo ngành trọng điểm chất lượng cao của nhà trường, tiên phong áp\n                     dụng\n                     các phương pháp đào tạo hiện đại, tăng cường kết nối doanh nghiệp và quan hệ quốc tế\n                     nhằm\n                     mang lại môi trường học tập năng động, hiện đại, tiên tiến cho sinh viên và đáp ứng nhu\n                     cầu\n                     xã hội.\n                  </p>\n                  <p>Chương trình đào tạo của khoa được xây dựng theo CDIO với đóng góp từ các doanh nghiệp\n                     nhằm\n                     đảm bảo tính thực tiễn, đáp ứng các yêu cầu từ doanh nghiệp. Khoa hiện đào tạo 3 ngành\n                     bậc\n                     cao đẳng gồm:\n                  </p>\n                  <ul>\n                     <li>Ngành Công nghệ Thông tin</li>\n                     <li>Ngành Truyền thông &amp; Mạng máy tính</li>\n                     <li>Ngành Thiết kế đồ họa</li>\n                  </ul>\n               </div>\n               <a href=\"#\" class=\"school-introduction-read-more\">Xem thêm</a>\n            </div>\n            <div class=\"partner\">\n               <h2>Đối tác</h2>\n               <div class=\"gach\"></div>\n               <h4>Chứng nhận</h4>\n               <div class=\"row\">\n                  <div class=\"col-md col-6\">\n                     <img src=\"http://localhost/thietbitheduc/wp-content/uploads/2020/11/cac2c72ec1ee420dbbc262608bf11d1f.png\" alt=\"#\">\n                  </div>\n                  <div class=\"col-md col-6\">\n                     <img src=\"http://localhost/thietbitheduc/wp-content/uploads/2020/11/cisco.gif\" alt=\"#\">\n                  </div>\n                  <div class=\"col-md col\"></div>\n               </div>\n               <div class=\"intership\">\n                  <h4>Công ty thực tập</h4>\n                  <div class=\"row\">\n                     <div class=\"col-md col-6\">\n                        <img src=\"http://localhost/thietbitheduc/wp-content/uploads/2020/11/985813c7ecd5a4c0864ef08e94711dc4.png\" alt=\"#\">\n                     </div>\n                     <div class=\"col-md col-6\">\n                        <img src=\"http://localhost/thietbitheduc/wp-content/uploads/2020/11/49e7eaa899e3df3806d10573a174ecfb.png\" alt=\"#\">\n                     </div>\n                     <div class=\"col-md col-6\">\n                        <img src=\"http://localhost/thietbitheduc/wp-content/uploads/2020/11/0c9f3588bf264e2a76bbbabf54b569a6.png\" alt=\"\">\n                     </div>\n                  </div>\n                  <br>\n                  <div class=\"row\">\n                     <div class=\"col-md col-6\">\n                        <img src=\"http://localhost/thietbitheduc/wp-content/uploads/2020/11/49af9617a610b35963f79ec10a73d911.png\" alt=\"#\">\n                     </div>\n                     <div class=\"col-md col-6\">\n                        <img src=\"http://localhost/thietbitheduc/wp-content/uploads/2020/11/9e6df75452.png\" alt=\"#\">\n                     </div>\n                     <div class=\"col-md col-6\">\n                        <img src=\"http://localhost/thietbitheduc/wp-content/uploads/2020/11/ab53da7262d4492694390fbd8878ee47.gif\" alt=\"\">\n                     </div>\n                  </div>\n               </div>\n            </div>\n         </div>\n      </div>\n   </div>\n</div>\n<!-- /wp:html -->\n\n<!-- wp:html /-->', 'Trang chủ', '', 'inherit', 'closed', 'closed', '', '30-revision-v1', '', '', '2020-11-04 01:05:22', '2020-11-04 01:05:22', '', 30, 'http://localhost/thietbitheduc/2020/11/04/30-revision-v1/', 0, 'revision', '', 0),
